-- Table structure for application_status_histories
DROP TABLE IF EXISTS `application_status_histories`;
CREATE TABLE `application_status_histories` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `job_application_id` bigint unsigned DEFAULT NULL,
  `previous_status` enum('applied','under_review','phone_screen','technical_test','interview','final_interview','offer','accepted','rejected','withdrawn') COLLATE utf8mb4_unicode_ci NOT NULL,
  `new_status` enum('applied','under_review','phone_screen','technical_test','interview','final_interview','offer','accepted','rejected','withdrawn') COLLATE utf8mb4_unicode_ci NOT NULL,
  `notes` longtext COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `application_status_histories_created_by_foreign` (`created_by`),
  KEY `application_status_histories_updated_by_foreign` (`updated_by`),
  KEY `application_status_histories_job_application_id_index` (`job_application_id`),
  KEY `application_status_histories_previous_status_index` (`previous_status`),
  KEY `application_status_histories_new_status_index` (`new_status`),
  KEY `application_status_histories_created_at_index` (`created_at`),
  CONSTRAINT `application_status_histories_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `application_status_histories_job_application_id_foreign` FOREIGN KEY (`job_application_id`) REFERENCES `job_applications` (`id`) ON DELETE SET NULL,
  CONSTRAINT `application_status_histories_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for cache
DROP TABLE IF EXISTS `cache`;
CREATE TABLE `cache` (
  `key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `value` mediumtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `expiration` int NOT NULL,
  PRIMARY KEY (`key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for cache_locks
DROP TABLE IF EXISTS `cache_locks`;
CREATE TABLE `cache_locks` (
  `key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `owner` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `expiration` int NOT NULL,
  PRIMARY KEY (`key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for companies
DROP TABLE IF EXISTS `companies`;
CREATE TABLE `companies` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `website` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `industry` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `company_size` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `headquarters` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `founded_year` smallint DEFAULT NULL,
  `company_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `logo_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `glassdoor_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `linkedin_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `average_rating` decimal(3,2) DEFAULT NULL,
  `total_reviews` int unsigned DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `companies_name_index` (`name`),
  KEY `companies_created_by_index` (`created_by`),
  KEY `companies_updated_by_index` (`updated_by`),
  CONSTRAINT `companies_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `companies_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (3, 'Momagic Bangladesh Limited', 'https://momagic.com.bd/', 'IT Services and IT Consulting', '18', 'Dhaka, Dhaka', 2008, 'IT Services and IT Consulting', 'MoMagic Bangladesh Ltd. is the next generation Mobile tech company. Established in 2012 as JV between Momagic HK Ltd. and Edison Group Bangladesh Ltd.. We specialize in mobile entertainment services, with our distribution arms deeply embedded into handheld devices. We serve 15+ handset companies in Bangladesh, while many more companies choose us to monetize from their user groups and analytics everyday', 'logos/HPGuavHJHPj1ibd14GIz6adtkgslX0T1ThjFJnnB.jpg', '', 'https://www.linkedin.com/company/chakrihub/', '0.00', 0, 1, 1, '2025-09-25 06:54:04', '2025-09-25 06:54:13');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (4, 'Pathao', 'http://pathao.com', 'Software Development', '2217', 'Tajwar Center, Rd No. 19/A, Dhaka 1212', 2015, 'Software Development', 'Pathao is the fastest growing technology company in Bangladesh solving some of the country’s most challenging problems in logistics and transportation. We are dreamers, scientists, operators, and entrepreneurs. Our culture is progressive, non-hierarchical, meritocratic, and collegial. We are looking for high achievers who will go above and beyond their job descriptions to fulfil a shared vision. If you are entrepreneurial, seek to change society with technology, and want to super-charge your career out of the regular 9 to 5, then Pathao is the place for you.', 'logos/TnWi4iyFRnz59SadLj9Rx21cDkzqNqpClF6OvpJ9.jpg', 'https://www.glassdoor.com/Reviews/Pathao-Reviews-E1758349.htm', 'https://www.linkedin.com/company/pathao/about/', '0.00', 0, 1, NULL, '2025-09-25 07:14:48', '2025-09-25 07:14:48');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (5, 'Riseup Labs', 'https://riseuplabs.com/', 'Outsourcing and Offshoring Consulting', '268', 'Plot No-32, Natore Tower, Floor- 3, D/E Road-3, Dhaka 1230', 2009, 'Outsourcing and Offshoring Consulting', 'Riseup Labs is an ISO 9001 &amp; 27001 certified next-generation global IT service and technology solution provider company that helps enterprises reimagine their business and navigate their digital transformation. We harness the power of web 3.0, automation, analytics, IoT, cloud and emerging technologies to design &amp; develop innovative, intelligent, sustainable solutions and services.\r\n\r\nWe are  a purpose-driven and outcome-based technology partner that enables 100+ clients in more than 20 countries to adapt to digital transformation and make them successful. Our mission is to help enterprises achieve their business objectives by providing IT services &amp; technology solutions.\r\n\r\nWith over 13 years of experience in managing 700+ projects and working with global enterprises, like - UNICEF, UNDP, USAID, FAO, WHO, ATEC, BBC, Fhi360, Axiata, Murka, Safe-Guard, Swiss Marketing Systems, we expertly steer our clients through their digital journey. We partner with enterprises to simplify, strengthen and transform their business.\r\n\r\nWe ensure the highest level of certainty and satisfaction through a deep-set commitment to our clients and comprehensive industry expertise. To offer enterprises the maximum benefit of technologies, Riseup Labs offers an integrated portfolio of products, solutions and services through four different segments. These are: Consulting &amp; Design (CD), Engineering &amp; Development (ED), Managed Services (MS) and R&amp;D Services (RD).\r\n\r\nOur specialties include AI &amp; ML, Network Operation, Software Development, Blockchain Development, Metaverse Development, Game Development, Mobile App Development, Web Development, Augmented Reality Development, Virtual Reality Development, Mixed Reality Development, Extended Reality Development, BPO, Quality Assurance, IT Enabled Services (ITES), Simulation Services, Capacity Building for IT, Resource Augmentation, IT Staff Augmentation, outstaffing, BPO Voice and Non-voice Services, and many more.', 'logos/nQsoIGSlFatOlF43YIAfcYs8HvqwUJ7p8Im5Qkb0.jpg', 'https://www.glassdoor.com/Reviews/Riseup-Labs-Dhaka-Reviews-EI_IE569564.0,11_IL.12,17_IM1237.htm', 'https://www.linkedin.com/company/riseuplabs/', '3.90', 117, 1, NULL, '2025-09-25 07:22:37', '2025-09-25 07:22:37');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (6, 'Datascape IT Limited', 'https://www.datascapeit.com/', 'Advertising Services', '14', 'Dhaka, Bangladesh', 2016, 'Advertising Services', 'Datascape IT Limited Provide, ERP Software, Customized ERP Software, Sales &amp; Inventory Software, HRM Software, Mobile Apps, Digital Marketing Agency, Experts in Social Media Marketing, SEO, Branding &amp; Advertising.', 'logos/EK3dC9CoswePtaqpdM64OLWU4VAGpeLjMaxmeMEK.jpg', 'https://www.glassdoor.com/Reviews/Datascope-Reviews-E1323.htm', 'https://www.linkedin.com/company/datascapeit/', '0.00', 17, 1, NULL, '2025-09-25 07:54:16', '2025-09-25 07:54:16');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (7, 'V2 Technologies Ltd', 'https://v2.ltd/', 'IT Services and IT Consulting', '44', 'Mohakhali DOHS, Dhaka', 2018, 'IT Services and IT Consulting', 'V2 Technologies Ltd. Is a Bangladesh based Information Technology Solution provider situated at the heart of Dhaka, the capital of Bangladesh. We help you get your business to the next level with the help of technology.\r\n\r\nAs a pure Technology Start Up, our main focus has been cutting edge technology and customer needs. We put our customer first. Comprising a bunch of young energetic people, we are always pushing ourselves for new business innovation and helping our clients to transform their business.\r\n\r\nFINDING GREAT PARTNER FOR YOUR BUSINESS AUTOMATION: \r\nWe take the time to genuinely listen to our clients. A scalable tech team you can grow or reduce as business demands, or staffing for short-term specialized projects, V2 gives you instant access to an Tech-Passionate team of technical professionals with up-to-the-minute skill sets.', 'logos/8sIQyOGnhpXwrQXwsMHavMoTBm3gJmHIWFHZvtop.jpg', 'https://www.glassdoor.com/Reviews/V2-Technologies-Reviews-E5602155.htm', 'https://www.linkedin.com/company/v2-tech-ltd/', '3.50', 12, 1, 1, '2025-09-25 09:03:35', '2025-09-25 09:13:01');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (8, 'Syntech Solution Limited', 'https://www.syntechbd.com/', 'Software Development', '57', 'Dhaka, Dhaka', 2006, 'Software Development', 'We would like to introduce ourselves as “Syntech Solution Ltd” which is an ISO certified renowned Software Development and Website design company in Bangladesh, which is able to provide you Affordable website design and all kind of IT solution. Syntech Start Business from 2006 and by this short time We archive a good name by continuous value added services.\r\n\r\nSynTech is a software engineering and consultancy firm focused on Web Based Application, &amp; software development, offshore web design, Website Development &amp; providing services to diverse customers. We provide Affordable Web Design. We have vision to provide enterprise solution to local and international organizations. If anyone want to wish outsource to Bangladesh you are most welcome to Syntech. Syntech Solution Ltd will provide you the best web design service in Bangladesh.\r\n\r\nWe believes in quality performance and We always serving the clients with the best possible solutions. Standardized development procedure, quality assurance and after sales support are some of the key features of SynTech.We are one of the leading offshore outsourcing company in Bangladesh. we always welcome people to outsource their project in Bangladesh.\r\n\r\nSynTech offers promising and innovative Website Design in Bangladesh and Search Engine Optimization Services by maintaining standard quality, on time delivery, cost-effective and many more. Syntech ensures the best Quality, Service, and most Competitive Price within the deadline.', 'logos/Xa05gfZEfPmOsvfcTyMDZIN3XxvGzXeffMtZZjdl.jpg', 'https://www.glassdoor.com/Reviews/Syntech-Solution-Reviews-E5377463.htm', 'https://www.linkedin.com/company/syntech-solution-ltd/', '2.80', 16, 1, NULL, '2025-09-25 11:43:06', '2025-09-25 11:43:06');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (11, 'Matrix Platform Ltd', 'https://www.matrixglobalplatform.com/', 'Apparel Manufacturing', '30', 'Kowloon, Hong Kong', 2020, 'Apparel Manufacturing', 'Matrix Platform Ltd is a global end-to-end sourcing and manufacturing platform serving many brands and retailers. Our operations are spread across 4 countries, 500+ employees, and a network of 10+ offices with over 15+ designers for Apparel products. Matrix offers our retail partners a broad spectrum of products. Leveraging global strengths, we provide a complete solution from design to production for apparel products. Digitization enables innovation, efficiency, and creates new ways of doing business. With our keen design sense, extensive industry experience, and adoption of the latest techniques and technologies, we are catering to the fast-evolving tastes and consumer preferences. Our vision for sustainability is the bedrock of our growth strategy. Driven by an integrated approach, we truly believe that concern for the environment is key to business growth in the industry. Be it working with like-minded partners, manufacturing products within our own facilities, complying with environment-friendly practices, everything is done to realize our vision of attaining social and ecological equilibrium.', 'logos/Nsy8OODcqofThlLXDkWb3IaaZQLaxEVIhRGTqxzX.jpg', '', 'https://www.linkedin.com/company/matrix-platform-ltd/', '0.00', 0, 1, NULL, '2025-09-28 07:22:00', '2025-09-28 07:22:00');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (12, 'FringeCore_', 'https://fringecore.sh/', 'Software Development', '16', 'Dhaka, Dhaka', 2023, 'Software Development', 'A team of engineers and designers making taming chaos in business by doing what we do best; build systems.', 'logos/hTABeJamzZEaltXj2nRhOnl37d3tWHxGd3IrHS5e.jpg', '', 'https://www.linkedin.com/company/fringecore/', '5.00', 2, 1, NULL, '2025-09-30 07:18:49', '2025-09-30 07:18:49');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (13, 'Skyline Digital Solutions', 'https://skylinedigitalsolutions.tech/', 'Software Development', '11', 'Road 1, Niketon, House - 33, Flat - 4A, Dhaka, BD', 2017, 'Software Development', 'Overview\r\nSkyline Digital Solutions is a hybrid software-product studio dedicated to turning bold ideas into reality. By blending in-office collaboration with remote flexibility, we’ve built a culture where our developers thrive, innovate, and deliver exceptional products end to end.\r\n\r\nWhat We Do\r\n	•	Product Strategy &amp;amp; Roadmapping\r\nCollaborate to clarify vision, prioritize features, and chart a development path that maximizes impact.\r\n	•	UX/UI Design\r\nCraft intuitive, engaging interfaces that delight users and drive adoption.\r\n	•	Full-Stack Development\r\nLeverage modern frameworks and best practices—from scalable backends to responsive frontends—to build robust, maintainable software.\r\n	•	Quality Assurance &amp;amp; Testing\r\nEnsure rock-solid stability and performance through comprehensive automated and manual testing.\r\n	•	Ongoing Maintenance &amp;amp; Growth\r\nProvide post-launch support, performance tuning, and feature enhancements to keep products evolving.\r\n\r\nOur Mission\r\nTo bring ideas to life as software products that delight users, accelerate business growth, and leave a lasting impact—while empowering our developers every step of the way.\r\n\r\nOur Vision\r\nA world where every organization, regardless of size, has access to best-in-class software—and every developer has the autonomy, tools, and support to excel.\r\n\r\nCore Values\r\n	•	Developer Empowerment: Invest in mentorship, training, and a culture of continuous learning.\r\n	•	Hybrid Flexibility: Blend collaborative office days with remote autonomy for maximum creativity and productivity.\r\n	•	Customer Obsession: Listen deeply, iterate rapidly, and deliver real value.\r\n	•	Craftsmanship: Uphold uncompromising quality in code, design, and service.\r\n	•	Integrity &amp;amp; Respect: Act with honesty, accountability, and mutual respect in every interaction.', 'logos/TjtylSIkiDvDDshJdjn311lCvg5bc3uWwcttw3YQ.jpg', 'https://www.glassdoor.com/Overview/Working-at-Skyline-Digital-Group-EI_IE2070028.11,32.htm', 'https://www.linkedin.com/company/skyline-digital-solutions-365/', '0.00', 0, 1, NULL, '2025-10-07 07:31:03', '2025-10-07 07:31:03');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (14, 'Paragon Group', 'https://www.paragongroup-bd.com/', 'Manufacturing', '610', 'Paragon House (Floor # 10), 5 Mohakhali C/A, Dhaka-1212', 1989, 'Manufacturing', 'Overview\r\nParagon Group is one of the leading agro-based companies in Bangladesh. These are the following sectors under the group. \r\n\r\nAnimal Feed, Poultry, Plastic Woven Bags, FIBC, Consumer products, Tea gardens, Bistro/ Cafe, Retail, Solar Energy, Bio gas energy, Fisheries, Organic Fertiliser, Flour mill, Foot ware and Dairy.', 'logos/l9HJARCSyc2avcXKOTQolZaTuCt0XKygFsA32nTF.jpg', 'https://www.glassdoor.com/Overview/Working-at-Paragon-Group-Bangladesh-EI_IE7504738.11,35.htm', 'https://www.linkedin.com/company/paragon-group-bd/about/', '4.50', 3, 1, NULL, '2025-10-07 07:42:47', '2025-10-07 07:42:47');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (15, 'W3 Engineers Ltd.', 'https://w3engineers.com/', 'IT Services and IT Consulting', '110', 'W3 Engineers Ltd. World Business Centrum 4th Floor, 76/A,Banani-11, Dhaka-1213, Bangladesh.', 2009, 'IT Services and IT Consulting', 'Overview\r\nW3 Engineers Ltd. is a technology innovations lab constructed to build blockchain, mesh, cloud, mobile, IoT and big data applications. Providing services to internal and external clients. W3 Engineers creates solutions to some of the world’s biggest challenges—the biggest of which is connectivity. They are the first to develop apps powered by RightMesh mobile mesh networking technology which enables connectivity even when no Internet or cellular service is available. Learn more at: https://w3engineers.com', 'logos/huxtVZFV3bN1txOWPKCyEDO7VDI5K8dwMTRQ7YSJ.jpg', 'https://www.glassdoor.com/Reviews/W3-Engineers-Software-Engineer-Reviews-EI_IE3438225.0,12_KO13,30.htm', 'https://www.linkedin.com/company/w3engineers/about/', '2.30', 57, 1, 1, '2025-10-08 08:17:44', '2025-10-08 08:52:59');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (16, 'Airwork AI', 'https://airwork.ai/', 'Software Development', '15', 'Palo Alto, California', 2022, 'Software Development', 'Overview\r\nAirwork AI is a global recruiting engine connecting ambitious companies with top global talent. With PrecisionHire™, we source, vet, and deliver 90%+ match shortlists in under 24 hours - while enabling skilled professionals to access high-quality global opportunities.', 'logos/qj2dnTynFUcIfoi61fDO7aE7D5mZ2aVJyn17GmEE.svg', '', 'https://www.linkedin.com/company/airworkai/about/', '0.00', 0, 1, NULL, '2025-10-08 09:01:35', '2025-10-08 09:01:35');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (17, 'Micronetbd', '', '', '48', 'Hamilton, New Jersey', 2012, 'Software Development', 'Overview\r\nMicronetbd is a professional, SOC2 Type 2, SAM, and NJ MBE Certified,  Salesforce Ridge (Silver) Partner, and DocuSign Consulting Partner. As a B2B company and Salesforce consultant, we are here to ensure that our customers unlock the true power of Salesforce and use it to grow their business. Our commitment is to value and professionalism, and we can help solve marketing, client services, sales, acquisition integration, and many other problems. \r\nWe work with Salesforce and other similar solutions in order to assist and help expand small or midsize financial services companies. What makes Micronetbd unique is that we always provide state-of-the-art, fully customized solutions and guidance for every client. Our approach is designed to help enhance customer satisfaction, boost productivity and automate any repetitive tasks.\r\nWhy choose us?\r\nThe Micronetbd team has been offering Salesforce related services since 2012, so we have 10+ years of experience in this field. We always stay up to date with the latest Salesforce features and implement everything at the highest possible level. When you work with us, you will have no problem getting fully customized, professional services that you can always rely on.\r\nAdditionally, we can help with pretty much everything related to Salesforce. This includes Salesforce career services, system integration, custom development, but also marketing cloud, service cloud, and sales cloud solutions. \r\nIf you want to harness the true power of Salesforce with fast, easy-to-use solutions, don’t hesitate and contact us today. We have a simple, yet comprehensive process that helps our customers access amazing results at the best prices on the market!', 'logos/4nxOUFVpaEck74pVBZXdgROisFvSkO47zqrwVS1g.jpg', 'https://www.glassdoor.com/Reviews/Micronetbd-Reviews-E2953348.htm', 'https://www.linkedin.com/company/micronetbd-inc/about/', '5.00', 17, 1, NULL, '2025-10-08 10:50:04', '2025-10-08 10:50:04');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (18, 'SoftBD Ltd', 'https://softbdltd.com', 'IT Services and IT Consulting', '50', '8th, 11th &amp; 13th Floor, 52/1 Hasan Holdings, New Eskaton Road', 2006, '', 'SoftBD Ltd is an information technology and services company based out of Bangladesh.', 'logos/yG7OB2VLmhG61VpBlYgnmNEX6XgXzCHWVcSubHBx.png', 'https://www.glassdoor.com/Overview/Working-at-Soft-BD-EI_IE4553371.11,18.htm', 'https://www.linkedin.com/company/softbd-ltd/about/', '0.00', 0, 1, NULL, '2026-04-07 05:56:38', '2026-04-07 05:56:38');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (19, 'Sheba Innovations Ltd.', 'http://shebainnovations.com/', 'Technology, Information and Internet', '10', 'Khaja Tower, Level 8 Mohakhali, Dhaka, Bangladesh, Dhaka, Bangladesh, BD', 2023, 'Technology, Information and Internet', 'We are a dynamic and tech-savvy company leading the charge in revolutionizing online, virtual, and learning solutions. Our team consists of forward-thinking tech visionaries, adept problem solvers, and passionate professionals.', 'logos/xOP51YW47uxtc6asuuBVEwT138oe4uUXRilxl86y.jpg', '', 'https://www.linkedin.com/company/sheba-innovations-ltd/about/', '0.00', 0, 1, NULL, '2026-04-09 07:10:24', '2026-04-09 07:10:24');
INSERT INTO `companies` (`id`, `name`, `website`, `industry`, `company_size`, `headquarters`, `founded_year`, `company_type`, `description`, `logo_url`, `glassdoor_url`, `linkedin_url`, `average_rating`, `total_reviews`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (20, 'Enosis Solutions', 'http://www.enosisbd.com', 'Software Development', '458', 'House 27, Road 8, Gulshan, Dhaka, 1212, BD', 2004, 'Software Development', 'Enosis is a premier provider of software development and testing services. Having talented software engineers on board, we craft compelling web, desktop, and mobile applications for our clients.\r\n\r\nSince our inception, we have partnered with numerous companies and delivered operational gains to startup, emerging, and established  organizations in the United States and Canada.', NULL, '', 'https://www.linkedin.com/company/enosis-solutions/about/', '4.30', 423, 1, NULL, '2026-04-09 07:23:26', '2026-04-09 07:23:26');

-- Table structure for contacts
DROP TABLE IF EXISTS `contacts`;
CREATE TABLE `contacts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `company_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `designation` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `email` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `phone` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `linkedin_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `whatsapp` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contact_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `relationship` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `last_contacted_date` date DEFAULT NULL,
  `response_rate` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `helpful` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `contacts_company_id_index` (`company_id`),
  KEY `contacts_user_id_index` (`user_id`),
  KEY `contacts_contact_type_index` (`contact_type`),
  KEY `contacts_response_rate_index` (`response_rate`),
  KEY `contacts_last_contacted_date_index` (`last_contacted_date`),
  CONSTRAINT `contacts_company_id_foreign` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE CASCADE,
  CONSTRAINT `contacts_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for failed_jobs
DROP TABLE IF EXISTS `failed_jobs`;
CREATE TABLE `failed_jobs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `uuid` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `connection` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `queue` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `exception` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `failed_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `failed_jobs_uuid_unique` (`uuid`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for follow_ups
DROP TABLE IF EXISTS `follow_ups`;
CREATE TABLE `follow_ups` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `job_application_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `follow_up_date` date NOT NULL,
  `follow_up_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `contact_person` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `message_sent` text COLLATE utf8mb4_unicode_ci,
  `response_received` text COLLATE utf8mb4_unicode_ci,
  `response_time_hours` int DEFAULT NULL,
  `sentiment` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `next_action` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `reminder_set` tinyint(1) NOT NULL DEFAULT '0',
  `reminder_date` date DEFAULT NULL,
  `completed` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `follow_ups_job_application_id_index` (`job_application_id`),
  KEY `follow_ups_user_id_index` (`user_id`),
  KEY `follow_ups_follow_up_date_index` (`follow_up_date`),
  KEY `follow_ups_completed_index` (`completed`),
  KEY `follow_ups_reminder_date_index` (`reminder_date`),
  CONSTRAINT `follow_ups_job_application_id_foreign` FOREIGN KEY (`job_application_id`) REFERENCES `job_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `follow_ups_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for interviews
DROP TABLE IF EXISTS `interviews`;
CREATE TABLE `interviews` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `job_application_id` bigint unsigned NOT NULL,
  `interview_round` int NOT NULL DEFAULT '1',
  `interview_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `interviewer_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `interviewer_designation` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `scheduled_date` datetime DEFAULT NULL,
  `duration_minutes` int DEFAULT NULL,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `meeting_link` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `interview_format` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `preparation_notes` text COLLATE utf8mb4_unicode_ci,
  `questions_asked` text COLLATE utf8mb4_unicode_ci,
  `my_answers` text COLLATE utf8mb4_unicode_ci,
  `technical_topics` text COLLATE utf8mb4_unicode_ci,
  `coding_problems` text COLLATE utf8mb4_unicode_ci,
  `interview_feedback` text COLLATE utf8mb4_unicode_ci,
  `interviewer_feedback` text COLLATE utf8mb4_unicode_ci,
  `outcome` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `confidence_level` tinyint DEFAULT NULL,
  `difficulty_level` tinyint DEFAULT NULL,
  `overall_experience` tinyint DEFAULT NULL,
  `next_round_scheduled` tinyint(1) NOT NULL DEFAULT '0',
  `follow_up_required` tinyint(1) NOT NULL DEFAULT '0',
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `interviews_job_application_id_index` (`job_application_id`),
  KEY `interviews_interview_round_index` (`interview_round`),
  KEY `interviews_outcome_index` (`outcome`),
  KEY `interviews_scheduled_date_index` (`scheduled_date`),
  KEY `interviews_created_by_index` (`created_by`),
  KEY `interviews_updated_by_index` (`updated_by`),
  CONSTRAINT `interviews_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `interviews_job_application_id_foreign` FOREIGN KEY (`job_application_id`) REFERENCES `job_applications` (`id`) ON DELETE CASCADE,
  CONSTRAINT `interviews_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for job_applications
DROP TABLE IF EXISTS `job_applications`;
CREATE TABLE `job_applications` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `user_id` bigint unsigned DEFAULT NULL,
  `company_id` bigint unsigned DEFAULT NULL,
  `job_title` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `job_description` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `job_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `salary_range_min` int DEFAULT NULL,
  `salary_range_max` int DEFAULT NULL,
  `currency` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `work_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `employment_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `application_date` date DEFAULT NULL,
  `application_deadline` date DEFAULT NULL,
  `application_status` enum('applied','under_review','phone_screen','technical_test','interview','final_interview','offer','accepted','rejected','withdrawn') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'applied',
  `priority` enum('low','medium','high') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'medium',
  `source` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `referral_contact` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cover_letter_sent` tinyint(1) NOT NULL DEFAULT '0',
  `portfolio_sent` tinyint(1) NOT NULL DEFAULT '0',
  `expected_salary` int DEFAULT NULL,
  `notice_period` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `last_follow_up_date` date DEFAULT NULL,
  `next_follow_up_date` date DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `job_applications_user_id_index` (`user_id`),
  KEY `job_applications_company_id_index` (`company_id`),
  KEY `job_applications_application_status_index` (`application_status`),
  KEY `job_applications_priority_index` (`priority`),
  KEY `job_applications_application_date_index` (`application_date`),
  KEY `job_applications_application_deadline_index` (`application_deadline`),
  KEY `job_applications_next_follow_up_date_index` (`next_follow_up_date`),
  KEY `job_applications_created_by_index` (`created_by`),
  KEY `job_applications_updated_by_index` (`updated_by`),
  CONSTRAINT `job_applications_company_id_foreign` FOREIGN KEY (`company_id`) REFERENCES `companies` (`id`) ON DELETE SET NULL,
  CONSTRAINT `job_applications_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `job_applications_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `job_applications_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (3, 1, 3, 'Full Stack Developer', 'Description\r\n\r\nLocation: Gulshan Tejgaon Link Road,\r\n\r\nEmployment Type: Full-time\r\n\r\nExperience Required: Minimum 3 years\r\n\r\nEducation: Bachelor’s degree in Computer Science / Software Engineering / related field\r\n\r\nAbout the Role\r\nWe are looking for an experienced Full Stack Developer to join our dynamic team. The ideal candidate will have a solid understanding of modern web technologies and frameworks, with hands-on experience building scalable applications.\r\n\r\nKey Responsibilities\r\nDevelop, test, and maintain high-performance web applications.\r\n\r\n\r\nDesign and implement RESTful APIs and integrate third-party services.\r\n\r\n\r\nWork with front-end and back-end teams to deliver end-to-end solutions.\r\n\r\n\r\nOptimize applications for speed, security, and scalability.\r\n\r\n\r\nCollaborate with UI/UX designers to build modern, user-friendly interfaces.\r\n\r\n\r\nMaintain database schemas, perform query optimization, and ensure data integrity.\r\n\r\n\r\nWork with caching and message queues for high-performance architectures.\r\n\r\nRequirements\r\nSkills &amp;amp;amp;amp;amp; Expertise\r\nFrontend: React.js, Next.js, HTML5, CSS3, JavaScript (ES6+), TailwindCSS / Material UI\r\n\r\n\r\nBackend: Node.js with Express.js &amp;amp;amp;amp;amp; NestJS\r\n\r\n\r\nDatabases: MySQL, PostgreSQL\r\n\r\n\r\nCaching &amp;amp;amp;amp;amp; Messaging: Redis\r\n\r\n\r\nOther Skills:\r\n\r\n\r\nRESTful API design and integration\r\n\r\n\r\nAuthentication &amp;amp;amp;amp;amp; Authorization (JWT, OAuth)\r\n\r\n\r\nGit / GitHub / GitLab workflows\r\n\r\n\r\nDocker knowledge (optional but preferred)\r\n\r\n\r\nQualifications\r\nMinimum 3 years of experience in full-stack development.\r\n\r\n\r\nBachelor’s degree in Computer Science, Software Engineering, or a related field.\r\n\r\n\r\nStrong problem-solving, debugging, and analytical skills.\r\n\r\n\r\nSalary &amp;amp;amp;amp;amp; Benefits\r\n\r\nT/A,Mobile bill,Medical allowance,Performance bonus,Profit share,Weekly 2 holidays\r\nSalary Review: Yearly\r\nLunch Facilities: Partially Subsidize\r\nFestival Bonus: 2\r\nCompetitive base salary (Up to 70k BDT)\r\nTailored Training Programs to sharpen your skills and fast-track your future goals.', 'https://orkmanza.com/momagic-bd/job/requirement/68c1245b2a5e8/en', 0, 70, 'BDT', 'Gulshan Tejgaon Link Road,', 'Full-time', '', '2025-09-25', '2025-09-30', 'applied', 'medium', 'Linkedin', '', 0, 0, 800000, '1', 'TOP SKILL:\r\n\r\nFrontend: React.js\r\nNext.js\r\nHTML5\r\nCSS3\r\nJavaScript (ES6+)\r\nNode.js with Express.js &amp; NestJS\r\nMySQL\r\nPostgreSQ\r\nRedis\r\nGit / GitHub / GitLab workflows', '2025-09-25', '2025-09-26', 1, 1, '2025-09-25 07:03:46', '2025-09-25 07:09:09');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (4, 1, 4, 'Software Engineer (Backend)', 'Software Engineer (Backend)\r\nThe incumbent will have the responsibility to:\r\n\r\nDesign and develop high-performance, scalable backend systems and APIs\r\n\r\nBuild and maintain microservices architecture for our platform ecosystem\r\n\r\nOptimize database performance and implement efficient data storage solutions\r\n\r\nCollaborate closely with frontend teams to ensure seamless API integration and optimal data flow\r\n\r\nLead system architecture decisions that support both backend scalability and frontend requirements\r\n\r\nParticipate in cross-functional technical planning and feature development\r\n\r\nCollaborate with DevOps teams on deployment strategies and infrastructure scaling\r\n\r\nBridge the gap between backend services and frontend applications through effective API design\r\n\r\nThe incumbent should bring along:\r\n\r\nAt least 4 years of professional backend development experience\r\n\r\nBachelor&#039;s degree in Computer Science, Engineering, or related field\r\n\r\nStrong understanding of system design principles and scalability patterns\r\n\r\nExperience with performance optimization and bottleneck identification\r\n\r\nKnowledge of security best practices and implementation\r\n\r\nExperience with agile development methodologies\r\n\r\nTechnical Expertise:\r\n\r\nExperience in Backend Technologies such as Node.js, Go, NestJS, Express.js, Microservices Architecture RESTful &amp; GraphQL APIs, Message Queues &amp; Caching Strategies\r\n\r\nDatabase &amp; Data Management skills mainly using SQL &amp; NoSQL, while having experience in Database Performance Tuning &amp; Data Migration\r\n\r\nStrong DevOps &amp; Infrastructure skills such as Docker, Kubernetes, Cloud Platforms, CI/CD Pipelines, Monitoring &amp; Logging &amp; Load Balancing\r\n\r\nHere’s What You’ll Enjoy at Pathao!\r\n\r\nCompetitive salary package\r\n\r\nTwo annual festival bonuses\r\n\r\nLeave encashment \r\n\r\nComprehensive insurance coverage\r\n\r\nGratuity benefit\r\n\r\nLunch benefit\r\n\r\nPhone allowance', 'https://docs.google.com/forms/d/e/1FAIpQLSe43jHzl7AWhGSLkRQELod3TiqukQQ0EiYs-1nhu1A2JhKcXg/viewform', 0, 0, 'BDT', 'Tajwar Center, Rd No. 19/A, Dhaka 1212', 'Full-time', '', '2025-09-24', '2025-09-30', 'applied', 'high', 'Linkedin', '', 0, 0, 90000, '1', '', '2025-09-25', '2025-09-26', 1, NULL, '2025-09-25 07:17:29', '2025-09-25 07:17:29');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (5, 1, 5, 'Riseup Labs (NodeJs Developer)', 'Job Context:\r\n\r\nRiseup Labs is seeking a passionate and enthusiastic Node.js Developer to join our engineering team. This role is ideal for someone with 2+ years of experience (or strong academic/project background) who wants to grow in backend development, APIs for applications.\r\n\r\nJob Responsibilities:\r\n\r\nDevelop and maintain scalable backend services and APIs using Node.js\r\nWrite clean, efficient, and testable code following best practices\r\nCollaborate with frontend developers, product managers, and designers to deliver features\r\nOptimize application performance, reliability, and security\r\nImplement and maintain database schemas, queries, and integrations\r\nDebug, troubleshoot, and resolve production issues in a timely manner\r\nParticipate in code reviews and provide constructive feedback\r\nEducational Requirements:\r\n\r\nBSc in Computer Science and Engineering from any reputed public or private university.\r\nAdditional Requirements:\r\n\r\n2+ years of professional experience with Node.js (Express.js/Nest.js)\r\nStrong knowledge of JavaScript (ES6+) and asynchronous programming\r\nExperience with RESTful API design and development\r\nSolid understanding of databases (MySQL/PostgreSQL or MongoDB\r\nFamiliarity with version control (Git) and CI/CD pipelines\r\nGood understanding of software development life cycle and Agile practices\r\nAbility to write unit/integration tests (Jest/Mocha/Chai or similar)\r\nNice to Have:\r\n\r\nExperience with TypeScript\r\nKnowledge of microservices architecture and Docker\r\nFamiliarity with cloud platforms (AWS)\r\nGood knowledge of frontend frameworks (React, Vue)\r\nExperience with GraphQL\r\nWorkplace: \r\n\r\nOnsite\r\nSalary: \r\n\r\nNegotiable (Based on Skills &amp;amp; Experience)\r\nCompensation &amp;amp; Other Benefits:\r\n\r\nAnnual Performance Evaluation and Increment\r\nFestival Bonus (2)\r\nGroup Life and Health Insurance\r\nFull Subsidize Lunch\r\nAnnual Retreats\r\nWedding Bonus (As per company’s policy)\r\nCelebration of Events &amp;amp; Occasions\r\nTeam Outing\r\nTraining &amp;amp; Development by Organization Assigned Consultants\r\nWeekly 2 holidays (Friday &amp;amp; Saturday)\r\nPaid Time Off 24 days (CL &amp;amp; SL)\r\nMaternity Leave with benefit (As per company&amp;#039;s policy)\r\nPaternity Leave\r\nPublic holidays as per Riseup Labs calendar\r\nThe Application Process:\r\n\r\nTelephone Round;\r\nInterview with the Tech Team &amp;amp; Talent Acquisition Team;\r\nAn assignment/test to complete (if required);\r\nJob offer.\r\nNB: Only shortlisted candidates will be communicated in the recruitment process.', '', 0, 0, '', 'Plot No-32, Natore Tower, Floor- 3, D/E Road-3, Dhaka 1230', 'Full Time', '', '2025-09-24', '2025-09-30', 'applied', 'high', 'Linkedin', '', 0, 0, 90000, '', '', '2025-09-25', '2025-09-25', 1, NULL, '2025-09-25 07:26:49', '2025-09-25 07:26:49');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (7, 1, 7, 'Software Engineer', 'Job Description: Software Engineer\r\n\r\nPosition Summary:\r\nWe are seeking a talented and motivated Software Engineer to join our team. The ideal candidate will have a strong background in backend and full-stack development, cloud technologies, and scalable system design. This role involves building high-performance applications, integrating enterprise-level authentication systems, and contributing to innovative solutions across multiple domains.\r\n\r\nResponsibilities\r\nDesign, develop, and maintain scalable backend services and APIs using modern frameworks such as Express.js, NestJS, Gin, and FastAPI.\r\nCollaborate with front-end teams to deliver seamless user experiences using React.js and Next.js.\r\nArchitect, optimize, and maintain databases (MySQL, PostgreSQL, MongoDB, Redis) to ensure high availability and performance.\r\nImplement and manage authentication and authorization systems, including Azure Single Sign-On (SSO) for enterprise clients.\r\nDevelop and enhance automation workflows to improve onboarding, user management, and operational efficiency.\r\nOptimize media processing pipelines (image/video) by leveraging Dockerized microservices deployed on AWS ECS/ECR.\r\nDesign and deploy cloud-native applications using AWS services (EC2, ECS, ECR, S3, SQS, Lambda) and Azure cloud solutions (Blob Storage, SSO).\r\nImplement and maintain CI/CD pipelines with Docker and GitHub Actions to ensure reliable and automated deployments.\r\nWrite clean, maintainable, and testable code while participating in peer code reviews.\r\n\r\nQualifications\r\nBachelor’s degree in Computer Science, Engineering, or a related field.\r\nStrong programming skills in JavaScript, TypeScript, Go, Python.\r\nHands-on experience with backend frameworks and ORMs.\r\nSolid understanding of databases (relational and NoSQL) and caching solutions.\r\nExpertise in cloud platforms (AWS and Azure), containerization (Docker), and DevOps practices.\r\nProven ability to design, optimize, and scale large distributed systems.\r\nFamiliarity with project management and collaboration tools (Git, Jira, Postman, ClickUp).\r\nStrong problem-solving, debugging, and analytical skills.\r\nExcellent communication skills with the ability to work effectively in a collaborative environment.\r\n\r\n\r\nPreferred Experience:\r\nExperience in developing and scaling CRM platforms with secure user management.\r\nHands-on involvement in AI-powered audit platforms, including automated scoring and real-time dashboards.\r\nProven track record in building public-facing image or file-sharing platforms with optimized pipelines and high scalability.\r\n\r\nSubmit your resume at : hr@v2.ltd\r\nSubject line: Software Developer_Name', 'https://www.linkedin.com/company/v2-tech-ltd/posts/', 50000, 70000, 'BDT', 'Mohakhali, DOHS, Dhaka', 'Full-time', '', '2025-09-25', '2025-09-30', 'applied', 'high', 'Linkedin', '', 1, 0, 0, '', 'Cover Letter\r\n\r\nMd. Ripon Mia\r\nDhaka, Bangladesh\r\n+8801623-765846\r\nriponahmed2201@gmail.com\r\n\r\n\r\n25-09-2025\r\n\r\nHiring Manager\r\nV2 Technologies Ltd\r\nMohakhali DOHS, Dhaka\r\n\r\nDear Hiring Manager,\r\n\r\nI am excited to apply for the Software Engineer role at V2 Technologies Ltd. With 5+ years of experience in backend and full-stack development using Node.js, Laravel, React.js, and TypeScript, I have delivered scalable ERP, SCM, and e-commerce platforms for organizations such as BracNet, Teletalk, and Lafarge Holcim.\r\n\r\nMy expertise includes Express.js, NestJS, Dockerized microservices, CI/CD pipelines, along with strong database optimization (PostgreSQL, MySQL, MongoDB). I have designed APIs supporting 400k+ users, improved system efficiency by 35%, and implemented secure enterprise-grade authentication systems.\r\n\r\nI am eager to contribute my skills in cloud-native development, scalable architecture, and secure systems to support the innovative projects at V2 Technologies Ltd. I would welcome the opportunity to discuss how my experience can add value to your team.\r\n\r\nSincerely,\r\nMd. Ripon Mia', '2025-09-25', '2025-09-30', 1, 1, '2025-09-25 09:09:55', '2025-09-25 09:12:18');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (8, 1, 8, 'Software Engineer', 'Summary\r\nVacancy:\r\n04\r\nAge:\r\n25 to 35 years\r\nLocation: Dhaka\r\nSalary:\r\nNegotiable\r\nExperience:\r\n3 to 5 years\r\nPublished:\r\n18 Sep 2025\r\n\r\nTo access Application Insights Get Bdjobs Pro\r\nRequirements\r\n\r\nEducation\r\n\r\nBachelor of Science (BSc)\r\nBachelor in Engineering (BEngg)\r\nExperience\r\n\r\n3 to 5 years\r\nThe applicants should have experience in the following business area(s): Software Company, IT Enabled Service, Computer Hardware/Network Companies, Web Media/Blog, E-commerce\r\nAdditional Requirements\r\n\r\nAge 25 to 35 years\r\nCandidate Must experience on large scale application development and implementation on live server.\r\nKnowledge about micro service based web application development.\r\nFamiliar with version control system - Git, Bitbucket\r\nResponsibilities &amp;amp; Context\r\n\r\nWe are looking for 3-5 years experienced Programmer.\r\n\r\nERP/CRM/Business Application projects in Laravel/JAVA Spring Boot Good at Angular JS/Vue JS/REACT Analyze, design and develop dynamic Web Application based on project documents.\r\n\r\nWeb Application Development using Laravel/JAVA Spring Boot and Vue.js. Applicant Must have well understanding on Javascript and Javascript Based Framwork.\r\n\r\nPerform complete unit testing of Web applications to specifications and standards. Brainstorming the conceptual design for new &amp;amp; existing projects.\r\n\r\nOvercome critical technical challenges with or without supervision specifically with Laravel/JAVA Spring Boot MySQL, Ajax and REST.\r\n\r\nQuickly learn and implement new technologies/skills when something unknown is encountered.\r\n\r\nCompensation &amp;amp; Other Benefits\r\n\r\nWeekly 2 holidays\r\nLunch Facilities: Partially Subsidize\r\nSalary Review: Yearly\r\nFestival Bonus: 2\r\nWorkplace\r\n\r\nWork at office\r\n\r\nEmployment Status\r\n\r\nFull Time\r\n\r\nJob Location\r\n\r\nDhaka\r\n\r\nApply Procedure\r\n\r\nEmail Your CV\r\n\r\nSend your CV to the given email syntechbd@gmail.com\r\n\r\nCompany Information\r\n\r\nSyntech Solution Limited\r\n\r\nFollow\r\nMore jobs from this company\r\nAddress:\r\n\r\nHouse:45, Road:20, Mohakhali D.O.H.S,Dhaka 1212.\r\n\r\nBusiness:\r\n\r\nSYNTECH SOLUTION LTD is a software engineering and consultancy firm focused on software development &amp;amp; providing services to a diverse customers. As Syntech is a BASIS Enlisted &amp;amp; ISO 9001:2008 Certified Company, Always trying to provide best service to Local and International Clients.', 'https://bdjobs.com/jobs/details/1408842?ln=1', 0, 0, 'BDT', 'House-45, Road-20, Mohakhali DOHS. Dhaka-1206, Bangladesh', 'Full Time', '', '2025-09-25', '2025-09-30', 'applied', 'medium', 'BDJobs', '', 0, 0, 0, '', 'Summary\r\nVacancy:\r\n04\r\nAge:\r\n25 to 35 years\r\nLocation: Dhaka\r\nSalary:\r\nNegotiable\r\nExperience:\r\n3 to 5 years\r\nPublished:\r\n18 Sep 2025\r\n\r\n\r\nApply Through Mail', '2025-09-25', '2025-09-30', 1, 1, '2025-09-25 11:45:18', '2025-09-25 11:51:23');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (10, 1, 12, 'Software Engineer', 'Fringecore_ is hiring once again!\r\nΣ View All Openings: https://fringecore.sh/careers\r\n💪 Apply: https://fringecore.sh/apply\r\nHi, we’re FringeCore, a team of engineers and desginers that make business processes crazy efficient through building software, hacking hardware and applying design thinking. We’re looking for a few persons to join our squad.\r\n✨ Vibe Check:\r\nYou understand that a surprisingly large part of engineering is communication with other humans who may or may not be engineers. (btw, we consider having a blog a plus)\r\nThe programming languages and frameworks are the least important part of software development because stacks become outdated but core concepts are never out of fashion.\r\nYou appreciate how knowledge from any part of life becomes of use somehow in every other part of life including at work.\r\n⚙️ Hiring Process:\r\nWe will contact you over SMS and Email in the coming weeks. You will have a short at-home coding challenge. Everyone who successfully completes and submits the challenge will be invited to a group adda at our office (this is the main interview). There may or may not be a one-on-one interview afterward.\r\n🎓 Educational Requirements: None required. Fresh graduates, dropouts, PhD holders, and people who don’t believe in institutional education are all welcome.\r\n⏰ Time Commitment: Full Time, on-premise, 10 AM to 6 PM. Slightly Flexible.\r\n📍 Location: Gulshan 2, Dhaka (near Gulshan 2 Circle)\r\n🍽 Lunch is on us. Unlimited Coffee.\r\n⌛ Deadline: 7th October, 11:59 pm\r\n.\r\n.\r\nFrontend Engineer\r\n🧮 Openings: 2\r\n🛰️ Position: Software Engineer\r\n⭐ Specialization: Frontend\r\n🔍 What We’re Looking For:\r\nJavaScript: In-depth understanding of the language itself (if you know what closures are, and how the functional array functions work, you’re good to go). Familiarity with TypeScript and generic types is a plus.\r\nReactJS: Understand the primitives, everything else is cake. (If you know when to use useMemo you’re on the right track)\r\nFamiliarity with any state management library (Redux, Zustand, MobX, etc).\r\n💰 Compensation:\r\nCompensation: 40K - 60K / Month\r\nFestival Bonuses\r\n.\r\n.\r\nBackend engineer\r\n🧮 Openings: 2\r\n🛰️ Position: Software Engineer\r\n⭐ Specialization: Backend\r\n🔍 What We’re Looking For:\r\nJavaScript: In-depth understanding of the language itself (if you know how prototypical inheritance works, and what closures are, you’re good to go). Familiarity with TypeScript and generic types is a plus.\r\nNodeJS: (Node Streams API is like super important)\r\nSQL: Experience with SQL databases (you can use JOINs and GROUP BY? pls apply.)\r\nFamiliarity with the Unix CLIs is a plus.\r\n💰 Compensation:\r\nCompensation: 40K - 60K / Month\r\nFestival Bonuses', 'https://www.facebook.com/groups/devforhire/posts/2312707719176287/', 40, 60, 'BDT', 'Gulshan 2, Dhaka (near Gulshan 2 Circle)', '', '', '2025-09-30', '2025-10-07', 'applied', 'high', 'Facebook', '', 1, 0, 0, '', 'I’m a backend engineer with 5+ years of experience in JavaScript, Node.js (including Streams API), and SQL. I’ve built large-scale ERP, SCM, and e-commerce systems using Node.js, Laravel, PostgreSQL, and MongoDB. I enjoy solving performance challenges—like optimizing queries with JOINs and GROUP BY—and working with Unix CLI tools.', '2025-09-30', '2025-10-02', 1, NULL, '2025-09-30 07:29:02', '2025-09-30 07:29:02');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (11, 1, 13, 'Software Engineer – Backend (Level 2)', 'Software Engineer – Backend (Level 2)\r\nOpenings: 2\r\nExperience: 3–5 years\r\n💼 Open Positions:\r\n ✅ 2x Sr. Software Engineer – Backend (L3) - {1,20,000 - 1,50,000}\r\n ✅ 2x Software Engineer – Backend (L2) - {60,000 - 80,000}\r\n ✅ 2x Software Engineer – Backend (L1) - {30,000 - 50,000}\r\n ✅ 2x Sr. Software Engineer – Frontend (L2) - {60,000 - 80,000}\r\n ✅ 2x Software Engineer – Frontend (L1) - {30,000 - 50,000}\r\n ✅ 3x Flutter Developer (L2) - {80,000 - 1,00,000}\r\n ✅ 1x UI/UX Designer - {60,000 - 80,000}\r\n\r\nKey Responsibilities:\r\nDevelop backend applications and APIs using Laravel and modern PHP practices.\r\nImplement RESTful and GraphQL APIs to serve dynamic frontend needs.\r\nWork with message queues (RabbitMQ, Kafka) for asynchronous processing.\r\nSupport and develop features like push notifications, chat, and real-time updates.\r\nWrite efficient queries and optimize performance for relational and non-relational databases.\r\nContribute to API documentation, code reviews, and modular architecture discussions.\r\nParticipate in container-based deployments and basic CI/CD processes.\r\nRequired Skills &amp;amp;amp; Experience:\r\nProficient in Laravel, modern PHP, and backend best practices.\r\nSolid experience building and consuming REST and GraphQL APIs.\r\nHands-on with message brokers (RabbitMQ, Kafka preferred).\r\nFamiliar with WebSocket, Webhooks, and push notification systems.\r\nGood knowledge of Docker, Git, and development workflow tools.\r\nExperience in building or integrating real-time features is a strong advantage.\r\nProblem-solving mindset and willingness to take ownership', 'https://docs.google.com/forms/d/e/1FAIpQLSeBqw4JbpIGLc0uU6ZX90hiJug4vbUeXRvVXr8SYRtwjfIYMQ/viewform', 0, 0, 'BDT', 'House 33, Road 1, Block A, Niketon, Gulshan, Dhaka 1212', 'Full-time (On-site)', '', '2025-10-07', '2025-10-08', 'applied', 'medium', 'Linkedin', '', 1, 0, 85000, '', 'Cover Letter:\r\n\r\nI’m a backend-focused software engineer with over five years of experience building scalable systems using Laravel, Node.js, and modern PHP. I specialize in developing RESTful and GraphQL APIs, optimizing database performance, and implementing real-time features with WebSockets and message queues like RabbitMQ. I also work with Docker, Git, and CI/CD pipelines to ensure smooth deployment and system scalability.', '2025-10-07', '2025-10-08', 1, 1, '2025-10-07 07:37:17', '2025-10-08 08:14:52');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (12, 1, 14, 'Sr. Developer (Full Stack Software)', 'Paragon Group\r\nSr. Developer (Full Stack Software)\r\nApplication Deadline :\r\n\r\n16 Oct 2025\r\n\r\nApply Now\r\n\r\nShortlist\r\nShare:\r\n\r\nFacebook\r\nLinkedIn\r\nWhatsApp\r\n\r\nAll\r\nRequirements\r\nResponsibilities\r\nSkills &amp; Expertise\r\nSalary &amp; Benefits\r\nCompany Information\r\n\r\nSummary\r\nVacancy:\r\n--\r\nAge:\r\n30 to 40 years\r\nLocation: Dhaka\r\nSalary:\r\nNegotiable\r\nExperience:\r\n5 to 10 years\r\nPublished:\r\n25 Sep 2025\r\n\r\nTo access Application Insights Get Bdjobs Pro\r\nRequirements\r\n\r\nEducation\r\n\r\nBachelor of Science (BSc) in Computer Science &amp; Engineering\r\nExperience\r\n\r\n5 to 10 years\r\nThe applicants should have experience in the following business area(s): Software Company, Group of Companies\r\nAdditional Requirements\r\n\r\nAge 30 to 40 years\r\nStrong expertise in:\r\n\r\no Node.js, Express.js\r\no Laravel, PHP\r\no React.js, Next.js\r\no SQL, PostgreSQL, MySQL, MongoDB\r\nStrong knowledge, experience and proficiency on data relation and database query.\r\nProficient knowledge on Bootstrap and tailwind.\r\nSolid understanding of REST API design and development.\r\nExperience working with ERP systems and large-scale web applications.\r\nProficient in Git and version control systems.\r\nStrong analytical and problem-solving skills.\r\nExcellent communication and team collaboration abilities.\r\nExperience with microservices architecture.\r\nFamiliarity with containerization (Docker, Kubernetes).\r\nHands on experience on DevOps &amp; cloud services (AWS, Digital Ocean, Azure).\r\nBuild deployment processes and CI/CD pipelines.\r\nSkilled at architecting scalable, fault-tolerant systems for high-concurrency environments.\r\nDNS configuration with Cloudflare.\r\nExperience in Agile/Scrum methodologies.\r\nDemonstrated portfolio of previous work.\r\nAbility to work both independently and collaboratively in a fast-paced environment.\r\nExcellent communication skills and attention to detail.\r\nStrong analytical, problem-solving, and debugging abilities\r\nResponsibilities &amp; Context\r\n\r\nDesign, develop, and maintain web applications and ERP modules.\r\nBuild robust RESTful APIs using Node.js, Express.js, and Laravel. Design, build, and maintain secure APIs for seamless data exchange. Develop scalable and secure backend modules for participant and plan data. Optimize database and system performance to support high concurrency.\r\nDevelop interactive and responsive user interfaces using React.js and Next.js.\r\nDesign and optimize complex databases using MySQL, PostgreSQL, and MongoDB. Ability to create compound data relation for ERP &amp; Other application.\r\nCollaborate with cross-functional teams to define, design, and ship new features.\r\nTroubleshoot, debug and upgrade existing systems. Contribute to all phases of the development lifecycle, from requirements gathering to deployment.\r\nWrite clean, scalable, and maintainable code following best practices.\r\nConfigure Cloud/VM/Physical servers like Azure, AWS, Robi etc.\r\nParticipate in code reviews and technical discussions. Conduct thorough testing of web and mobile components to ensure performance, quality, functionality, responsiveness, and reliability.\r\nAbility to work under pressure, meet the deadline, eager to\r\nMentor developers and lead technical projects.\r\nPerform any other relevant assignment given by the supervisor.\r\nParagon Group is one of the largest business conglomerate in Bangladesh is inviting dynamic, self-driven and experienced candidates for for the position of Sr. Developer (Full Stack Software) .\r\nSkills &amp; Expertise\r\nExpress.js\r\nMongoDB\r\nMySQL\r\nNode js\r\nPostgreSQL\r\nreact.js\r\nSQL\r\nCompensation &amp; Other Benefits\r\n\r\nMobile bill,Gratuity\r\nLunch Facilities: Partially Subsidize\r\nSalary Review: Yearly\r\nFestival Bonus: 3\r\nExcellent working environment.\r\n\r\nStandard career path.\r\n\r\nOther benefits as per company policy.\r\n\r\nWorkplace\r\n\r\nWork at office\r\n\r\nEmployment Status\r\n\r\nFull Time\r\n\r\nJob Location\r\n\r\nDhaka', 'https://bdjobs.com/jobs/details/1411960?ln=1', 0, 0, 'BDT', 'Paragon House (Floor # 10), 5 Mohakhali C/A, Dhaka-1212', 'Full Time', '', '2025-10-07', '2025-10-16', 'applied', 'medium', 'BDJobs', '', 0, 0, 85000, '', 'Company Information\r\n\r\nParagon Group\r\n\r\nFollow\r\nMore jobs from this company\r\nAddress:\r\n\r\nParagon House (Floor # 10), 5 Mohakhali C/A, Dhaka-1212\r\n\r\nWebsite:\r\n\r\nwww.paragongroup-bd.com\r\nBusiness:\r\n\r\nParagon Group is one of the largest business conglomerate in the country. Main businesses are Poultry, Feeds, Dairy, FMCG, Plastic Bag, FIBC, Solar power, Footwear, etc.', '2025-10-07', '2025-10-16', 1, NULL, '2025-10-07 07:50:45', '2025-10-07 07:50:45');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (13, 1, 16, 'Backend Engineer', 'https://dhakaailab.com/\r\n\r\nBackend Engineer\r\nIntelligent Machines\r\nApply\r\nJob description\r\n\r\nOVERVIEW\r\n\r\nAt Intelligent Machines (IM), we turn massive datasets into strategic insights for major clients like BAT and IDLC. We&#039;re looking for a Junior Backend Engineer who can craft scalable APIs, manage databases, and ensure seamless data pipelines. If you&#039;re a TypeScript expert with backend chops and a hunger to work on real-world AI products, we want to meet you.\r\n\r\n\r\n\r\nRESPONSIBILITIES\r\n\r\nDevelop and maintain robust backend systems using Node.js/Express\r\nDesign and implement scalable RESTful APIs\r\nCollaborate with frontend and ML teams to ensure smooth data flow\r\nWrite clean, maintainable, and well-documented code\r\nOptimize performance and troubleshoot backend issues\r\nWork with cloud-based tools and CI/CD pipelines\r\nSupport integrations with third-party services and data sources\r\n\r\n\r\nMUST-HAVES\r\n\r\nJavaScript\r\nTypeScript\r\nNode.js\r\nExpress\r\nRESTful APIs\r\nSQL\r\nNoSQL\r\nGit\r\n\r\n\r\nSHOULD-HAVES\r\n\r\nPython\r\nFastAPI\r\nDeployment workflows\r\n\r\n\r\nNICE-TO-HAVES\r\n\r\nAWS\r\nGoogle Cloud Platform\r\nAzure\r\n\r\n\r\nCOMPENSATION\r\n\r\nSalary: 90K+ BDT per month\r\n\r\n(Higher salary for proven skills demonstrated during the interview)\r\n\r\n\r\n\r\nOTHER DETAILS\r\n\r\nFull-time\r\nNumber of vacancies: 1\r\n\r\n\r\nAPPLY TODAY\r\n\r\n⚡ Get fast-tracked to the final interview when recommended by Airwork.\r\n\r\nSkill requirements\r\n\r\nJavaScript\r\nTypeScript\r\nNode.js\r\nPython Flask or FastAPI\r\nSQL\r\nSQL/NoSQL\r\nExpress.js\r\nGit\r\nAWS\r\nAzure\r\nAbout company\r\n\r\n\r\nIntelligent Machines\r\n\r\nhttps://bangladesh.ai/\r\n\r\nWe build enterprise AI products and also provide data science services to help clients reach their organizational goals and objectives – • Delivered 12 AI products • Deployed 59 AI models, parsers, and algorithms • Live: 19 models, 23 parsers, and 3 algorithms (14 models have been decommissioned) • In-progress: 1 model and 9 parsers • 15 clients in five countries: Bangladesh, USA, Australia, UAE, and Myanmar\r\n\r\nIndustry\r\nTechnology Information and Internet\r\nPeople\r\n11-50 employees\r\nFounded\r\n2018\r\nHQ\r\nBangladesh', 'https://app.airwork.ai/jobs/68bd3b06d51cfd19fd2b8a66', 90000, 100000, 'BDT', 'Moar, Ventura Iconia, Level-3 House-37 Road-11 Block-H Banani, Dhaka-1213, Bangladesh', 'Full-time On-site Permanent', 'Senior', '2025-10-07', '2025-10-11', 'applied', 'high', 'Linkedin', '', 0, 0, 95000, '', '', '2025-10-08', '2025-10-11', 1, NULL, '2025-10-08 09:29:08', '2025-10-08 09:29:08');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (14, 1, 17, 'Full Stack Developer', 'We’re looking for an experienced Full Stack Developer with a strong focus on backend development using Node.js and modern web technologies. The ideal candidate will have deep experience building and scaling robust applications, designing secure APIs, and deploying cloud-based systems.\r\nResponsibilities\r\n•Design, develop, and maintain scalable backend systems using Node.js, Express.js, and PostgreSQL/MongoDB.\r\n•Build and optimize mobile and web interfaces using React Native and Vue3 frameworks.\r\n•Implement and maintain RESTful APIs with a focus on performance, reliability, and security.\r\n•Work with Docker, Kubernetes, and cloud platforms (AWS/GCP/Azure) for deployment and scalability.\r\n•Manage CI/CD pipelines and ensure quality using Jest, React Native Testing Library, and Detox.\r\n•Collaborate with cross-functional teams to deliver end-to-end product features and improve user experience.\r\n•Monitor, debug, and optimize system performance using tools.\r\nRequirements\r\n•4+ years of experience in full stack or backend development.\r\n•Strong expertise in Java, Node.js, React.js, Express.js, Vue 3, MongoDB, and PostgreSQL.\r\n•Experience with system scaling, including load balancing, horizontal scaling, and clustering.\r\n•Hands-on experience with Docker, Kubernetes, and at least one major cloud provider (AWS/GCP/Azure).\r\n•Knowledge of API design, security best practices, and performance optimization.\r\n•Familiarity with CI/CD pipelines and monitoring tools.\r\n•Excellent problem-solving skills and attention to detail.\r\nNice to Have\r\n•Experience with Redis,RabbitMQ, Database, and scaling techniques.\r\n•Familiarity with React or Next.js for front-end development.\r\nWhy Join Us\r\n•Work on challenging, high-impact projects.\r\n•An excellent opportunity to learn, grow, and contribute within a dynamic global corporate environment. \r\n•Collaborate with a passionate and skilled engineering team.\r\n•Competitive salary and opportunities for growth\r\n•Fully subsidize food and snacks facilities.\r\n•2 Days weekly leave\r\n•Yearly salary review. \r\n📩 Contact\r\nIf you’re interested in joining our team, please send your resume to:\r\n 📧 Email:hrteam@micronetbd.org\r\n 🌐 Website: https://micronetbd.org, \r\n  Linkedin: https://www.linkedin.com/company/micronetbd-inc\r\nLocation: Micronetbd (Banani)', 'https://www.facebook.com/100063522342026/posts/1393067616153970/?rdid=b0mCLWkhiMePVeAs#', 0, 0, 'BDT', 'Micronetbd (Banani)', 'Full-time', '', '2025-10-08', '2025-10-30', 'applied', 'medium', 'Facebook', '', 1, 0, 0, '', '', '2025-10-08', '2025-10-30', 1, NULL, '2025-10-08 10:59:14', '2025-10-08 10:59:14');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (15, 1, 18, 'Full Stack Software Developer', 'Full Stack Software Developer\r\nVacancies: 4 • Experience: 2 to 5 years • Last date to apply: 10 Apr 2026\r\n\r\nExpressJs JavaScript MongoDB MySQL NestJS NextJS NodeJS PHP PostgreSQL Python ReactJS\r\n\r\nAre you an adaptable and passionate software engineer with 2-5 years of experience in the tech industry?\r\n\r\nDo you thrive in problem-solving, and are you excited about staying at the cutting edge of technology?\r\n\r\nAre you motivated to tackle complex challenges and contribute to groundbreaking software solutions?\r\n\r\nIf so, we want you to be a part of our dynamic team at Soft BD LTD.\r\n\r\n \r\n\r\nKey Responsibilities:\r\n\r\nSoftware Development\r\n\r\nCollaborate with cross-functional teams to design, develop, and maintain scalable, high-performance software applications that make a real impact.\r\nProblem-Solving\r\n\r\nUse your analytical skills to overcome technical challenges, ensuring software is reliable, efficient, and performs under pressure.\r\nWeb Development\r\n\r\nBuild and maintain robust, monolithic, and microservice-based web applications using JavaScript/PHP/Python while ensuring quality code and optimal performance.\r\nFrontend Development\r\n\r\nCreate user-friendly, dynamic interfaces and web applications using React.js/Next.js and Vue.js/Nuxt.js, focusing on usability, responsiveness, and an exceptional user experience.\r\nBackend Development\r\n\r\nDesign and develop scalable API-driven applications using PHP/Laravel, Node.js/Nest.js/Express.js, and Python/Django, enabling seamless integration and functionality.\r\nDatabase Management\r\n\r\nLeverage your expertise in MySQL, PostgreSQL, and MongoDB (NoSQL) to optimize database architecture, ensuring data integrity, scalability, and efficiency.\r\nCode Quality &amp;amp;amp;amp; Best Practices\r\n\r\nMaintain high coding standards by writing clean, efficient, and maintainable code, adhering to industry best practices and standards.\r\nWhy Join Soft BD LTD?\r\n\r\nInnovative Projects: Work on cutting-edge software solutions that are shaping the future of the industry.\r\nCareer Growth: With continuous learning opportunities, we support your professional development and help you advance in your career.\r\nInclusive Culture: We believe in fostering a diverse, collaborative, and inclusive work environment where every voice is heard.\r\nDevelopment Resources: We provide access to a wide range of resources to support your skills growth and career progression.\r\nEmployee Benefits:\r\n\r\nCompetitive Salary: Enjoy a competitive salary along with performance-based incentives.\r\nFlexible Work Environment: Work alongside a talented and innovative team in a collaborative setting.\r\nProfessional Development: We invest in your career growth, offering opportunities to enhance your technical skills and expertise.\r\nAdditional Perks:\r\nTransport Allowance (T/A)\r\nProvident Fund\r\nTwo-day weekend (Friday and Saturday)\r\nTwo Festival Bonuses\r\n \r\n\r\nIf you&amp;amp;amp;#039;re ready to take on new challenges and shape the future of software development, we’d love to hear from you! Apply today to join a team that&amp;amp;amp;#039;s making a difference.', 'https://hrpayroll.softbd.xyz/job-posts/2', 70000, 85000, 'BDT', '', 'Full Time', '', '2026-04-07', '2026-04-10', 'applied', 'low', 'Linkedin', '', 1, 0, 85000, '', 'Cover Letter\r\nDear Hiring Manager,\r\n\r\nI am interested in the Full Stack Software Developer position at Soft BD LTD.\r\n\r\nWith 5+ years of experience in Laravel, Node.js, NestJS, React.js, MySQL, PostgreSQL, and MongoDB, I have worked on scalable systems including ERP, SCM, e-commerce, and ticketing platforms.\r\n\r\nCurrently, I am working on legacy system modernization and API-driven application development, which aligns well with the responsibilities of this role.\r\n\r\nI would welcome the opportunity to contribute to your team.\r\n\r\nSincerely,\r\nMd. Ripon Mia\r\n\r\nDescribe a complex system you designed or significantly contributed to. *\r\n\r\nOne of the most complex systems I contributed to is the modernization of the bdtickets platform at Reddot Digital Limited. It is a large-scale ticketing system with modules such as inventory, booking engine, agent and counter sales, call center operations, accounting, API integrations, and payment gateway workflows.\r\n\r\nThe system was built on a legacy PHP (Zend Framework) and Java architecture with limited documentation and tightly coupled logic. My role involved reverse-engineering the system, understanding business workflows, and helping transform monolithic components into modern API-driven services using Laravel and NestJS.\r\n\r\nI contributed to backend design, API development, documentation, and system modernization while ensuring scalability, maintainability, and backward compatibility. This project required solving complex technical and business challenges in a production environment.', '2026-04-07', '2026-04-07', 1, 1, '2026-04-07 10:22:35', '2026-04-07 10:23:17');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (16, 1, 19, 'Senior Backend Engineer', 'Senior Backend Engineer\r\n\r\n📍 Location: Shyamoli, Dhaka\r\n🕒 Job Type: Full-time\r\n📅 Deadline: April 20, 2026\r\n\r\nAbout the Role\r\n\r\nWe are looking for a Senior Backend Engineer to design, develop, and maintain scalable backend services and APIs. The ideal candidate should have strong expertise in Node.js, NestJS, Express, and database systems, along with hands-on experience in microservices, WebSocket, REST API, and GraphQL.\r\n\r\nThis role requires someone who can contribute to backend architecture, system performance, code quality, testing, and mentoring junior developers.\r\n\r\nResponsibilities\r\nDesign, develop, and maintain backend API services\r\nImplement and work with microservices architecture\r\nWork with MySQL and MongoDB databases\r\nDevelop and integrate WebSocket using Socket.io\r\nConduct code reviews and mentor junior developers\r\nCollaborate with product, frontend, and DevOps teams\r\nContribute to architecture and design decisions\r\nOptimize backend performance, troubleshoot issues, and ensure reliability\r\nImplement RESTful APIs and GraphQL APIs\r\nWrite unit tests and integration tests\r\nMonitor logs, metrics, and dashboards\r\nRequirements\r\nStrong experience with Node.js\r\nHands-on expertise in NestJS and Express.js\r\nSolid understanding of MySQL and MongoDB\r\nExperience with REST API and GraphQL\r\nExperience with Socket.io / WebSocket\r\nGood understanding of microservices architecture\r\nFamiliarity with testing practices (unit &amp; integration testing)\r\nStrong problem-solving and debugging skills\r\nAbility to work collaboratively in a team environment\r\nGood communication and mentoring capability\r\nNice to Have\r\nExperience with WebRTC\r\nFamiliarity with React.js\r\nFamiliarity with Next.js\r\nEmployment Details\r\nWorkplace: Work at office\r\nEmployment Status: Full-time\r\nOffice Location: Shyamoli, Dhaka\r\nApplication Process\r\n\r\n📩 Send your updated CV to:\r\nhr@shebainnovations.com\r\n\r\n📌 Subject Line:\r\nSenior Backend Engineer\r\n\r\n📅 Application Deadline:\r\nApril 20, 2026', '', 60000, 60000, 'BDT', 'shyamoli', 'Full Time', '', '2026-04-09', '2026-04-20', 'applied', 'low', 'Facebook', '', 1, 0, 60000, '', '', '2026-04-09', '2026-04-21', 1, NULL, '2026-04-09 07:15:31', '2026-04-09 07:15:31');
INSERT INTO `job_applications` (`id`, `user_id`, `company_id`, `job_title`, `job_description`, `job_url`, `salary_range_min`, `salary_range_max`, `currency`, `location`, `work_type`, `employment_type`, `application_date`, `application_deadline`, `application_status`, `priority`, `source`, `referral_contact`, `cover_letter_sent`, `portfolio_sent`, `expected_salary`, `notice_period`, `notes`, `last_follow_up_date`, `next_follow_up_date`, `created_by`, `updated_by`, `created_at`, `updated_at`) VALUES (17, 1, 20, 'Senior Software Engineer', 'Enosis Solutions - Home\r\nSenior Software Engineer\r\nWe are looking for Senior Software Engineers having professional experience and good knowledge of web application development. Your primary focus will be developing scalable and maintainable enterprise-level web applications for customers following proper design patterns and clean code in a timely manner.\r\nKey Responsibilities\r\nDesign, code, test, and implement according to software design specifications following standard coding styles and practices.\r\nAnalyze the requirements and understand the deliverables.\r\nEnsure that projects are accurately estimated and delivered to schedule.\r\nParticipate in code/design reviews.\r\nCollaborate with team members and ensure knowledge transfer.\r\nActively contribute to the process of continual improvement, concerning self, team, and systems.\r\nRequired Skills &amp;amp; Qualifications\r\n2 to 4 years of experience in software development.\r\nB.Sc in Computer Science/Engineering or equivalent.\r\nMust have strong knowledge of any major programming language, like C/C++, C#, .NET, Java, PHP, Python, JavaScript, etc.\r\nMust have strong knowledge of Web technologies like HTML, CSS, and Javascript.\r\nMust have strong experience with at least one backend framework (e.g., .NET Core, Spring, Laravel, Django etc.).\r\nKnowledge of any SPA framework is a plus.\r\nMust be familiar with any relational database, like Microsoft SQL Server, MySQL, Oracle, etc.\r\nMust have good knowledge of object-oriented software development.\r\nMust have strong communication skills in English, both written and spoken.\r\nMust have very strong analysis and synthesis skills.\r\nMust be able to learn new technologies, tools, and techniques quickly and with minimal supervision.\r\nMust be proactive and able to execute tasks eﬃciently.\r\nBenefits\r\nPerformance-based bonus\r\nEid festival bonus\r\nHybrid work model\r\nComplementary meals and snacks\r\nTwo weekly holidays\r\nAbout Enosis Solutions\r\nEnosis Solutions is an engineering powerhouse and trusted partner for software development and testing services. We design and develop web, desktop, and mobile applications for our clients that are compelling, interactive, and easy to use. Since our inception, we have been providing operational gains to startup, emerging, and established organizations throughout North America and Europe.\r\nApply Now\r\nOur Hiring Process\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\nApply Now\r\nApplication Deadline\r\nApril 30, 2026\r\nDepartment\r\nEngineering\r\nEmployment Type\r\nPermanent - Full Time\r\nLocation\r\nDhaka\r\nWorkplace type\r\nHybrid\r\nCompensation\r\n৳85,000 - ৳115,000 / month\r\nView all opportunities at Enosis Solutions\r\nEnosis Solutions\r\nPrivacy Policy\r\nCookies\r\nPowered by', 'https://enosisbd.pinpointhq.com/en/postings/c4e2a15c-1b24-470a-8294-32d242797ad5', 85000, 115000, 'BDT', 'House 27, Road 8, Gulshan, Dhaka, 1212, BD', 'Full Time', 'Permanent - Full Time', '2026-04-09', '2026-04-30', 'applied', 'low', 'Linkedin', '', 0, 0, 85000, '', '', '2026-04-09', '2026-05-01', 1, NULL, '2026-04-09 07:28:06', '2026-04-09 07:28:06');

-- Table structure for job_batches
DROP TABLE IF EXISTS `job_batches`;
CREATE TABLE `job_batches` (
  `id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `total_jobs` int NOT NULL,
  `pending_jobs` int NOT NULL,
  `failed_jobs` int NOT NULL,
  `failed_job_ids` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `options` mediumtext COLLATE utf8mb4_unicode_ci,
  `cancelled_at` int DEFAULT NULL,
  `created_at` int NOT NULL,
  `finished_at` int DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for jobs
DROP TABLE IF EXISTS `jobs`;
CREATE TABLE `jobs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `queue` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payload` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `attempts` tinyint unsigned NOT NULL,
  `reserved_at` int unsigned DEFAULT NULL,
  `available_at` int unsigned NOT NULL,
  `created_at` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  KEY `jobs_queue_index` (`queue`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Table structure for migrations
DROP TABLE IF EXISTS `migrations`;
CREATE TABLE `migrations` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `migration` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `batch` int NOT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

